/**
 * Validation helper module.
 *
 * Each validator returns an array of error strings (empty = valid).
 * Use `buildErrors` to compose multiple field validators together.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators — each returns a (possibly empty) array of strings
// ---------------------------------------------------------------------------

/**
 * Asserts a value is present (not undefined, null, or empty string).
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return [`"${fieldName}" is required`];
  }
  return [];
}

/**
 * Asserts a value is a string (only checked when value is present).
 */
function validateString(value, fieldName) {
  if (value !== undefined && value !== null && typeof value !== 'string') {
    return [`"${fieldName}" must be a string`];
  }
  return [];
}

/**
 * Asserts a string length is within [min, max] (inclusive).
 * Skipped when value is absent or not a string.
 */
function validateStringLength(value, fieldName, min, max) {
  if (typeof value !== 'string') return [];
  if (value.length < min || value.length > max) {
    return [`"${fieldName}" must be between ${min} and ${max} characters`];
  }
  return [];
}

/**
 * Asserts a value is a valid email address (RFC 5321-ish, max 254 chars).
 * Skipped when value is absent or not a string.
 */
function validateEmail(value, fieldName) {
  if (typeof value !== 'string') return [];

  // Basic structural check: local@domain with a dot in the domain part.
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return [`"${fieldName}" must be a valid email address`];
  }
  return [];
}

/**
 * Asserts a value can be coerced to a positive integer (route :id params
 * arrive as strings, so we accept both numeric strings and actual numbers).
 */
function validateNumericId(value, fieldName) {
  if (value === undefined || value === null) return [];

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return [`"${fieldName}" must be a positive integer`];
  }
  return [];
}

// ---------------------------------------------------------------------------
// Composite field schemas
// ---------------------------------------------------------------------------

/**
 * Validates a `name` field: required, string, 1–100 chars.
 */
function validateNameField(value, { required = true } = {}) {
  const errors = [];
  if (required) errors.push(...validateRequired(value, 'name'));
  if (errors.length === 0 || value !== undefined) {
    errors.push(...validateString(value, 'name'));
    if (typeof value === 'string') {
      errors.push(...validateStringLength(value, 'name', 1, 100));
    }
  }
  return errors;
}

/**
 * Validates an `email` field: required, string, valid format, max 254 chars.
 */
function validateEmailField(value, { required = true } = {}) {
  const errors = [];
  if (required) errors.push(...validateRequired(value, 'email'));
  if (errors.length === 0 || value !== undefined) {
    errors.push(...validateString(value, 'email'));
    if (typeof value === 'string') {
      errors.push(...validateEmail(value, 'email'));
      errors.push(...validateStringLength(value, 'email', 1, 254));
    }
  }
  return errors;
}

/**
 * Validates a route `:id` parameter: present and numeric.
 */
function validateIdParam(value) {
  const errors = [];
  errors.push(...validateRequired(value, 'id'));
  errors.push(...validateNumericId(value, 'id'));
  return errors;
}

// ---------------------------------------------------------------------------
// Middleware factories
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that validates `req.params.id`.
 * Responds 400 with descriptive errors if validation fails.
 */
function validateParamId() {
  return (req, res, next) => {
    const errors = validateIdParam(req.params.id);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

/**
 * Returns an Express middleware that validates the request body for
 * creating a new user (name + email both required).
 */
function validateCreateUserBody() {
  return (req, res, next) => {
    const { name, email } = req.body || {};
    const errors = [
      ...validateNameField(name, { required: true }),
      ...validateEmailField(email, { required: true }),
    ];
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

/**
 * Returns an Express middleware that validates the request body for
 * updating a user (name + email optional, but validated when present).
 * At least one field must be provided.
 */
function validateUpdateUserBody() {
  return (req, res, next) => {
    const { name, email } = req.body || {};
    const errors = [];

    // At least one field must be supplied
    if (name === undefined && email === undefined) {
      errors.push('At least one field ("name" or "email") must be provided');
    }

    if (name !== undefined) {
      errors.push(...validateNameField(name, { required: false }));
    }
    if (email !== undefined) {
      errors.push(...validateEmailField(email, { required: false }));
    }

    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Low-level validators (useful for unit tests)
  validateRequired,
  validateString,
  validateStringLength,
  validateEmail,
  validateNumericId,

  // Composite field validators
  validateNameField,
  validateEmailField,
  validateIdParam,

  // Express middleware factories
  validateParamId,
  validateCreateUserBody,
  validateUpdateUserBody,
};

