/**
 * validation.js — reusable input-validation helpers
 *
 * Each validator returns an array of error strings.
 * An empty array means the input is valid.
 */

/** Matches the RFC 5321/5322 practical e-mail format (max 254 chars enforced separately). */
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID supplied as a URL parameter or query string value.
 * Accepts numeric strings ("42") as well as actual numbers.
 *
 * @param {*} id - Value to check.
 * @returns {string[]} Array of validation error messages.
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point running further checks
  }

  const num = Number(id);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the "name" field from a request body.
 *
 * @param {*} name - Value to check.
 * @param {boolean} [required=true] - Whether the field must be present.
 * @returns {string[]} Array of validation error messages.
 */
function validateName(name, required = true) {
  const errors = [];

  if (name === undefined || name === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors; // length checks are meaningless on non-strings
  }

  const trimmed = name.trim();
  if (trimmed.length < 1) {
    errors.push('name must be at least 1 character');
  } else if (trimmed.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  return errors;
}

/**
 * Validate the "email" field from a request body.
 *
 * @param {*} email - Value to check.
 * @param {boolean} [required=true] - Whether the field must be present.
 * @returns {string[]} Array of validation error messages.
 */
function validateEmail(email, required = true) {
  const errors = [];

  if (email === undefined || email === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  if (!EMAIL_RE.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the full user body expected on POST /users.
 * Both "name" and "email" are required.
 *
 * @param {object} body - Parsed request body.
 * @returns {string[]} Combined list of all validation errors.
 */
function validateCreateUser(body) {
  if (!body || typeof body !== 'object') {
    return ['request body must be a JSON object'];
  }

  return [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
}

/**
 * Validate the user body expected on PUT /users/:id.
 * At least one of "name" or "email" must be provided; whichever
 * fields are present are fully validated.
 *
 * @param {object} body - Parsed request body.
 * @returns {string[]} Combined list of all validation errors.
 */
function validateUpdateUser(body) {
  if (!body || typeof body !== 'object') {
    return ['request body must be a JSON object'];
  }

  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    return ['at least one field (name, email) must be provided for update'];
  }

  return [
    ...(hasName ? validateName(body.name, true) : []),
    ...(hasEmail ? validateEmail(body.email, true) : []),
  ];
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};

