const express = require('express');
const {
  validateId,
  validateCreateUser,
  validateUpdateUser,
} = require('./validation');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory "database" (replace with a real DB in production)
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Send a 400 response that lists every validation error that was found.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

// GET /health — liveness probe (no user input, no validation needed)
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users — list all users
// ---------------------------------------------------------------------------
app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// POST /users — create a new user
//
// Required body fields: name (string, 1–100 chars), email (valid, ≤254 chars)
// ---------------------------------------------------------------------------
app.post('/users', (req, res) => {
  const errors = validateCreateUser(req.body);
  if (errors.length > 0) {
    return sendValidationError(res, errors);
  }

  const { name, email } = req.body;

  const newUser = { id: nextId++, name: name.trim(), email };
  users.push(newUser);

  res.status(201).json(newUser);
});

// ---------------------------------------------------------------------------
// GET /users/:id — retrieve a single user
//
// URL param: id (positive integer)
// ---------------------------------------------------------------------------
app.get('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length > 0) {
    return sendValidationError(res, idErrors);
  }

  const id = Number(req.params.id);
  const user = users.find((u) => u.id === id);

  if (!user) {
    return res.status(404).json({ error: `User with id ${id} not found` });
  }

  res.json(user);
});

// ---------------------------------------------------------------------------
// PUT /users/:id — update an existing user
//
// URL param: id (positive integer)
// Body fields (at least one required):
//   name  — string, 1–100 chars
//   email — valid email, ≤254 chars
// ---------------------------------------------------------------------------
app.put('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length > 0) {
    return sendValidationError(res, idErrors);
  }

  const bodyErrors = validateUpdateUser(req.body);
  if (bodyErrors.length > 0) {
    return sendValidationError(res, bodyErrors);
  }

  const id = Number(req.params.id);
  const userIndex = users.findIndex((u) => u.id === id);

  if (userIndex === -1) {
    return res.status(404).json({ error: `User with id ${id} not found` });
  }

  const { name, email } = req.body;
  if (name !== undefined) users[userIndex].name = name.trim();
  if (email !== undefined) users[userIndex].email = email;

  res.json(users[userIndex]);
});

// ---------------------------------------------------------------------------
// DELETE /users/:id — remove a user
//
// URL param: id (positive integer)
// ---------------------------------------------------------------------------
app.delete('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length > 0) {
    return sendValidationError(res, idErrors);
  }

  const id = Number(req.params.id);
  const userIndex = users.findIndex((u) => u.id === id);

  if (userIndex === -1) {
    return res.status(404).json({ error: `User with id ${id} not found` });
  }

  const deleted = users.splice(userIndex, 1)[0];
  res.json({ message: `User ${id} deleted`, user: deleted });
});

// ---------------------------------------------------------------------------

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

