/**
 * Validation helper module.
 *
 * Each exported function returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Validate a route parameter that must be a positive integer id.
 *
 * @param {string} raw  - The raw string value from req.params
 * @returns {string[]}  - Validation errors (empty = valid)
 */
function validateId(raw) {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push('id is required');
    return errors;
  }

  const num = Number(raw);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate fields that may appear in a user request body.
 *
 * @param {object}   body           - req.body
 * @param {string[]} requiredFields - Fields that must be present and non-empty
 * @returns {string[]}              - Validation errors (empty = valid)
 */
function validateUserBody(body, requiredFields = []) {
  const errors = [];

  // ── Required-field presence check ──────────────────────────────────────────
  for (const field of requiredFields) {
    if (body[field] === undefined || body[field] === null || body[field] === '') {
      errors.push(`${field} is required`);
    }
  }

  // ── name ───────────────────────────────────────────────────────────────────
  if (body.name !== undefined) {
    if (typeof body.name !== 'string') {
      errors.push('name must be a string');
    } else {
      if (body.name.trim().length < 1) {
        errors.push('name must be at least 1 character');
      } else if (body.name.length > NAME_MAX) {
        errors.push(`name must be at most ${NAME_MAX} characters`);
      }
    }
  }

  // ── email ──────────────────────────────────────────────────────────────────
  if (body.email !== undefined) {
    if (typeof body.email !== 'string') {
      errors.push('email must be a string');
    } else {
      if (body.email.length > EMAIL_MAX) {
        errors.push(`email must be at most ${EMAIL_MAX} characters`);
      }
      if (!EMAIL_REGEX.test(body.email)) {
        errors.push('email must be a valid email address');
      }
    }
  }

  return errors;
}

/**
 * Convenience middleware factory: validates req.params.id and short-circuits
 * with a 400 if invalid.
 */
function requireValidId(req, res, next) {
  const errors = validateId(req.params.id);
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

module.exports = { validateId, validateUserBody, requireValidId };

