 * An empty array means all checks passed.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user id supplied as a route parameter or query value.
 * Accepts a string representation of a positive integer.
 *
 * @param {*} value  - raw value to check
 * @param {string} field - field label used in error messages
 * @returns {string[]} array of validation error messages
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`'${field}' is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`'${field}' must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a user name.
 *
 * @param {*} value - raw value to check
 * @param {string} field - field label used in error messages
 * @returns {string[]} array of validation error messages
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`'${field}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${field}' must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`'${field}' must be at least 1 character`);
  } else if (trimmed.length > 100) {
    errors.push(`'${field}' must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validate an email address.
 *
 * @param {*} value - raw value to check
 * @param {string} field - field label used in error messages
 * @returns {string[]} array of validation error messages
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`'${field}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${field}' must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`'${field}' must be at most 254 characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${field}' must be a valid email address`);
  }

  return errors;
}

/**
 * Validate all fields required to create a new user (POST).
 * Both 'name' and 'email' are required.
 *
 * @param {object} body - parsed request body
 * @returns {string[]} array of all validation error messages
 */
function validateCreateUser(body) {
  const errors = [];
  errors.push(...validateName(body.name));
  errors.push(...validateEmail(body.email));
  return errors;
}

/**
 * Validate all fields for a full user update (PUT).
 * Both 'name' and 'email' are required.
 *
 * @param {object} params - route params (must include id)
 * @param {object} body   - parsed request body
 * @returns {string[]} array of all validation error messages
 */
function validateUpdateUser(params, body) {
  const errors = [];
  errors.push(...validateId(params.id));
  errors.push(...validateName(body.name));
  errors.push(...validateEmail(body.email));
  return errors;
}

/**
 * Validate fields for a partial user update (PATCH).
 * At least one of 'name' or 'email' must be present; present fields
 * are fully validated.
 *
 * @param {object} params - route params (must include id)
 * @param {object} body   - parsed request body
 * @returns {string[]} array of all validation error messages
 */
function validatePatchUser(params, body) {
  const errors = [];

  errors.push(...validateId(params.id));

  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push("at least one of 'name' or 'email' must be provided");
    return errors;
  }

  if (hasName) {
    errors.push(...validateName(body.name));
  }
  if (hasEmail) {
    errors.push(...validateEmail(body.email));
  }

  return errors;
}

/**
 * Validate a delete request (only the route id is needed).
 *
 * @param {object} params - route params (must include id)
 * @returns {string[]} array of all validation error messages
 */
function validateDeleteUser(params) {
  return validateId(params.id);
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validatePatchUser,
  validateDeleteUser,
};

