 * Validation helper module.
 *
 * Each validate* function returns an array of error message strings.
 * An empty array means the data is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user id supplied as a route parameter or query value.
 * Accepts both numeric strings ("42") and actual numbers.
 *
 * @param {*}      value     - The raw value to check.
 * @param {string} [field]   - Field label used in error messages (default "id").
 * @returns {string[]} Validation errors (empty = valid).
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // no point running further checks
  }

  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    errors.push(`"${field}" must be a numeric integer (received: ${JSON.stringify(value)})`);
  } else if (num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name field.
 *
 * Rules:
 *  - required (non-empty after trim)
 *  - must be a string
 *  - length: 1–100 characters
 *
 * @param {*}      value
 * @param {string} [field]
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string (received: ${typeof value})`);
    return errors; // length checks are meaningless on non-strings
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters (received: ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email field.
 *
 * Rules:
 *  - required
 *  - must be a string
 *  - must match a basic email format  (RFC-5321 local@domain)
 *  - max 254 characters (RFC-5321 limit)
 *
 * @param {*}      value
 * @param {string} [field]
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string (received: ${typeof value})`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
    return errors;
  }

  if (trimmed.length > 254) {
    errors.push(`"${field}" must be at most 254 characters (received: ${trimmed.length})`);
  }

  if (!EMAIL_REGEX.test(trimmed)) {
    errors.push(`"${field}" must be a valid email address (received: ${JSON.stringify(trimmed)})`);
  }

  return errors;
}

/**
 * Validate the body of a create-user (POST) request.
 * Both "name" and "email" are required.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate the body of an update-user (PUT) request.
 * Both "name" and "email" must be present when supplied, but at least
 * one must be provided (partial updates require explicit field inclusion).
 *
 * For simplicity (and to match the spec), both fields are required on PUT.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUpdateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Return a 400 JSON response with a structured error listing.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  return res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  sendValidationError,
};

