/**
 * validation.js
 * Reusable input-validation helpers for API route handlers.
 *
 * Usage:
 *   const { validateUser, validateId } = require('./validation');
 *
 *   const errors = validateUser(req.body);          // [] means valid
 *   const idErrors = validateId(req.params.id);     // [] means valid
 *
 *   if (errors.length) return res.status(400).json({ errors });
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitives
// ---------------------------------------------------------------------------

/**
 * Returns true when the value looks like a valid email address.
 * Uses the RFC 5321-friendly pattern that real-world validators accept.
 */
function isValidEmail(value) {
  // Local part @ domain, domain must have at least one dot
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return EMAIL_RE.test(value);
}

/**
 * Returns true when the value is (or can be parsed as) a finite integer > 0.
 */
function isNumericId(value) {
  const n = Number(value);
  return Number.isFinite(n) && Number.isInteger(n) && n > 0;
}

// ---------------------------------------------------------------------------
// Field-level validators — each returns an array of error strings (empty = OK)
// ---------------------------------------------------------------------------

function validateIdField(value, fieldName = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return errors; // no point checking further
  }

  if (!isNumericId(value)) {
    errors.push(`"${fieldName}" must be a positive integer (received: ${JSON.stringify(value)})`);
  }

  return errors;
}

function validateNameField(value, fieldName = 'name') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string (received: ${typeof value})`);
    return errors; // length check only makes sense on strings
  }

  if (value.length < 1 || value.length > 100) {
    errors.push(`"${fieldName}" must be between 1 and 100 characters (received length: ${value.length})`);
  }

  return errors;
}

function validateEmailField(value, fieldName = 'email') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string (received: ${typeof value})`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${fieldName}" must be at most 254 characters (received length: ${value.length})`);
  }

  if (!isValidEmail(value)) {
    errors.push(`"${fieldName}" must be a valid email address (received: ${JSON.stringify(value)})`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators — used directly in route handlers
// ---------------------------------------------------------------------------

/**
 * Validates the body payload for creating a user (POST /users).
 * All three fields are required.
 *
 * @param {object} body - req.body
 * @returns {string[]} Array of human-readable error messages; empty = valid.
 */
function validateCreateUser(body) {
  if (!body || typeof body !== 'object') {
    return ['Request body must be a JSON object'];
  }

  return [
    ...validateIdField(body.id),
    ...validateNameField(body.name),
    ...validateEmailField(body.email),
  ];
}

/**
 * Validates the body payload for updating a user (PUT /users/:id).
 * All three fields are required.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUpdateUser(body) {
  if (!body || typeof body !== 'object') {
    return ['Request body must be a JSON object'];
  }

  return [
    ...validateNameField(body.name),
    ...validateEmailField(body.email),
  ];
}

/**
 * Validates a URL parameter that must be a numeric ID.
 *
 * @param {string} paramValue - e.g. req.params.id
 * @returns {string[]}
 */
function validateNumericParam(paramValue, paramName = 'id') {
  return validateIdField(paramValue, paramName);
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // composite validators (primary public API)
  validateCreateUser,
  validateUpdateUser,
  validateNumericParam,

  // individual field validators (useful for custom combinations)
  validateIdField,
  validateNameField,
  validateEmailField,

  // primitives (useful for unit tests)
  isValidEmail,
  isNumericId,
};

