/**
 * Validation helper module.
 *
 * Each validator returns an array of error strings (empty = valid).
 * Compose them with `collectErrors` to produce a single error list.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators — each returns a string[] of failure messages
// ---------------------------------------------------------------------------

/**
 * Assert that every field name in `fields` is present (non-undefined, non-null,
 * non-empty-string) on `data`.
 */
function requireFields(data, fields) {
  const errors = [];
  for (const field of fields) {
    const value = data[field];
    if (value === undefined || value === null || value === '') {
      errors.push(`"${field}" is required`);
    }
  }
  return errors;
}

/**
 * Assert that `value` is a finite integer (or a string that parses to one).
 * Returns an error string or null.
 */
function validateId(value, label = 'id') {
  if (value === undefined || value === null) return null; // presence checked elsewhere
  const n = Number(value);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    return `"${label}" must be a numeric integer`;
  }
  if (n <= 0) {
    return `"${label}" must be a positive integer`;
  }
  return null;
}

/**
 * Assert that `value` is a non-empty string within [minLen, maxLen] characters.
 */
function validateStringLength(value, label, minLen, maxLen) {
  if (value === undefined || value === null) return null; // presence checked elsewhere
  if (typeof value !== 'string') {
    return `"${label}" must be a string`;
  }
  const len = value.length;
  if (len < minLen) {
    return `"${label}" must be at least ${minLen} character${minLen !== 1 ? 's' : ''} long`;
  }
  if (len > maxLen) {
    return `"${label}" must be at most ${maxLen} characters long`;
  }
  return null;
}

/**
 * Assert that `value` matches a standard email format and respects the
 * RFC 5321 maximum address length of 254 characters.
 */
function validateEmail(value, label = 'email') {
  if (value === undefined || value === null) return null; // presence checked elsewhere
  if (typeof value !== 'string') {
    return `"${label}" must be a string`;
  }
  // Basic but practical email regex: local@domain.tld
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `"${label}" must be a valid email address`;
  }
  if (value.length > 254) {
    return `"${label}" must be at most 254 characters long`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite validators for common shapes
// ---------------------------------------------------------------------------

/**
 * Validate a user body object (name + email).
 * `requiredFields` lets callers control which fields are mandatory
 * (e.g. a PATCH endpoint may make both optional).
 */
function validateUserBody(body, requiredFields = ['name', 'email']) {
  const errors = [];

  errors.push(...requireFields(body, requiredFields));

  const nameErr = validateStringLength(body.name, 'name', 1, 100);
  if (nameErr) errors.push(nameErr);

  const emailErr = validateEmail(body.email);
  if (emailErr) errors.push(emailErr);

  return errors;
}

/**
 * Validate a route parameter that should be a positive integer id.
 */
function validateIdParam(params, label = 'id') {
  const errors = [];
  const err = validateId(params[label], label);
  if (err) errors.push(err);
  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Build an Express middleware that runs `validatorFn(req)` and responds with
 * 400 + descriptive errors if any are found.
 *
 * `validatorFn` receives the full `req` object and must return string[].
 *
 * Usage:
 *   router.post('/users', validate(req => validateUserBody(req.body)), handler);
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  requireFields,
  validateId,
  validateStringLength,
  validateEmail,
  validateUserBody,
  validateIdParam,
  validate,
};

