/**
 * Validation helper module.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the value passed all checks.
 *
 * The top-level `validate` helper composes multiple field validators,
 * collects every failure, and sends a structured 400 response when
 * there is at least one error.
 */

'use strict';

// ---------------------------------------------------------------------------
// Individual field validators
// ---------------------------------------------------------------------------

/**
 * Validate a route / query parameter that must be a numeric id.
 * Accepts both numbers and numeric strings (e.g. "42").
 *
 * @param {*}      value     - The raw value to test.
 * @param {string} [field]   - Field name used in error messages.
 * @returns {string[]}       - Array of validation errors (empty = valid).
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // no point in further checks
  }

  // Allow numeric strings that come in from URL params
  if (typeof value !== 'number' && typeof value !== 'string') {
    errors.push(`"${field}" must be a numeric value`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isFinite(num) || num !== Math.floor(num)) {
    errors.push(`"${field}" must be an integer`);
  } else if (num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name field.
 *
 * Rules:
 *  - required
 *  - must be a string
 *  - length 1–100 characters
 *
 * @param {*}      value
 * @param {string} [field]
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be blank`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters (got ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email field.
 *
 * Rules:
 *  - required
 *  - must be a string
 *  - must match a basic RFC-5321-compatible email pattern
 *  - max length 254 characters (RFC 5321 §4.5.3.1.3)
 *
 * @param {*}      value
 * @param {string} [field]
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  // Covers the vast majority of valid addresses without being overly strict.
  // local part: printable chars excluding whitespace / @ ; domain: labels
  // separated by dots, each label is alphanumeric + hyphens.
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${field}" must be at most 254 characters (got ${value.length})`);
  }

  if (!EMAIL_RE.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators
// ---------------------------------------------------------------------------

/**
 * Validate the full user body (name + email).
 * Suitable for POST (create) requests where both fields are required.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUserBody(body = {}) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate the user body for PATCH / PUT (update) requests.
 * At least one of name or email must be present; only the supplied
 * fields are validated.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUserUpdateBody(body = {}) {
  const errors = [];

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one of "name" or "email" must be provided');
    return errors;
  }

  if (hasName)  errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmail(body.email));

  return errors;
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * Run one or more validation functions, collect all errors, and — if there
 * are any — send a 400 response and return `true` (so the caller can
 * `return` immediately).
 *
 * Usage inside a route handler:
 *
 *   if (validate(res, () => validateId(req.params.id), () => validateUserBody(req.body))) return;
 *
 * @param {import('express').Response} res
 * @param {...function(): string[]}    validators  - Zero-arg functions that
 *                                                   return error arrays.
 * @returns {boolean} `true` when the response has been sent (validation
 *                    failed); `false` when everything passed.
 */
function validate(res, ...validators) {
  const errors = validators.flatMap((fn) => fn());

  if (errors.length > 0) {
    res.status(400).json({
      error:   'Validation failed',
      details: errors,
    });
    return true; // response sent
  }

  return false; // all good
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validateUserUpdateBody,
  validate,
};
